/**
 * Faraday's law — two-panel illustration of the classic bar-magnet-and-coil
 * demonstration. Left panel: magnet at rest near a coil, galvanometer reads
 * zero. Right panel: magnet moving toward the coil, galvanometer needle
 * deflects (current induced by the changing flux).
 *
 * Geometry generated by Gemini 3.1 Pro v2 (after coil-readability fixes —
 * coils now drawn as visible elliptical wire turns instead of a hatched
 * rectangle).
 *
 * Source: /tmp/gemini-svg/faraday_demo_v2_3.1_Pro.svg
 *
 * Labels (S, N, G, v, I, captions) wired through i18n.
 */
import { useTranslation } from 'react-i18next'

export default function FaradayDemoDiagram() {
  const { t } = useTranslation('ui')

  return (
    <figure className="mx-auto my-4 max-w-[640px] not-prose">
    <svg
      viewBox="0 0 640 245"
      fill="none"
      aria-label={t('ch1_6.faradayDemoAria')}
      role="img"
      xmlns="http://www.w3.org/2000/svg"
      className="block w-full h-auto"
    >
      {/* Layer 1: magnet pole tints (S faint, N stronger). Magnets are
          positioned right up against the coils — N pole within ~10–15 px
          of the coil's left end — so the magnet's field clearly threads
          the coil. With the magnet far away (the original layout had a
          75 px gap) the diagram misleadingly suggested no interaction. */}
      <rect x="105" y="78" width="40" height="24" fill="currentColor" opacity="0.05" />
      <rect x="145" y="78" width="40" height="24" fill="currentColor" opacity="0.15" />
      <rect x="425" y="78" width="40" height="24" fill="currentColor" opacity="0.05" />
      <rect x="465" y="78" width="40" height="24" fill="currentColor" opacity="0.15" />

      {/* Layer 2: motion lines behind the right magnet + panel divider */}
      <line x1="400" y1="84" x2="417" y2="84" stroke="currentColor" strokeWidth="1" opacity="0.6" />
      <line x1="395" y1="90" x2="417" y2="90" stroke="currentColor" strokeWidth="1" opacity="0.6" />
      <line x1="405" y1="96" x2="417" y2="96" stroke="currentColor" strokeWidth="1" opacity="0.6" />
      <line x1="320" y1="20" x2="320" y2="240" stroke="currentColor" strokeWidth="1" strokeDasharray="4 4" opacity="0.3" />

      {/* Layer 3 (was: coil cores) — REMOVED. Earlier the coil was drawn
          as upward-curving arcs sitting on top of an opaque rectangle, and
          the rectangle read as an unrelated box rather than a cylindrical
          form. The coil is now drawn entirely from slanted "/" front
          passes and faint "\\" back passes — same convention as the
          right-hand-rule coil panel — so no occluding form is needed. */}

      {/* Layer 4: front elements */}

      {/* Magnet outlines + S/N divider — left magnet at x=105–185
          (N pole right edge at 185, ~10 px from coil's left at 195),
          right magnet at x=425–505 (N pole right edge at 505, ~10 px
          from coil's left at 515). */}
      <rect x="105" y="78" width="80" height="24" stroke="currentColor" strokeWidth="1.5" fill="none" />
      <line x1="145" y1="78" x2="145" y2="102" stroke="currentColor" strokeWidth="1.5" />
      <rect x="425" y="78" width="80" height="24" stroke="currentColor" strokeWidth="1.5" fill="none" />
      <line x1="465" y1="78" x2="465" y2="102" stroke="currentColor" strokeWidth="1.5" />

      {/* Both coils use the SAME "\\" winding as the right-hand-rule coil
          panel: front passes slant from top-left to bottom-right; back
          passes (faint, drawn first) connect bottom-right of one turn to
          top-left of the next. Leads enter at the helix's natural
          endpoints — top-left of the first turn and bottom-right of the
          last turn — and route around the coil down to the galvanometer
          terminals. */}

      {/* Left coil — back passes (faint, drawn first) */}
      <path
        d="M 204 106 L 213 74 M 222 106 L 231 74 M 240 106 L 249 74 M 258 106 L 267 74"
        stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" opacity="0.3" fill="none"
      />
      {/* Left coil — front passes ("\\" diagonals) */}
      <path
        d="M 195 74 L 204 106 M 213 74 L 222 106 M 231 74 L 240 106 M 249 74 L 258 106 M 267 74 L 276 106"
        stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" fill="none"
      />

      {/* Right coil — back passes */}
      <path
        d="M 524 106 L 533 74 M 542 106 L 551 74 M 560 106 L 569 74 M 578 106 L 587 74"
        stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" opacity="0.3" fill="none"
      />
      {/* Right coil — front passes */}
      <path
        d="M 515 74 L 524 106 M 533 74 L 542 106 M 551 74 L 560 106 M 569 74 L 578 106 M 587 74 L 596 106"
        stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" fill="none"
      />

      {/* Left circuit leads — connect coil top-left (helix start) and
          coil bottom-right (helix end) to galvanometer terminals.
          Routed AROUND the coil so neither lead crosses the wire wraps. */}
      <polyline points="195,74 180,74 180,200" stroke="currentColor" strokeWidth="1.5" strokeLinejoin="round" fill="none" />
      <polyline points="276,106 276,140 140,140 140,200" stroke="currentColor" strokeWidth="1.5" strokeLinejoin="round" fill="none" />

      {/* Right circuit leads — same pattern */}
      <polyline points="515,74 500,74 500,200" stroke="currentColor" strokeWidth="1.5" strokeLinejoin="round" fill="none" />
      <polyline points="596,106 596,140 460,140 460,200" stroke="currentColor" strokeWidth="1.5" strokeLinejoin="round" fill="none" />

      {/* Left galvanometer */}
      <circle cx="160" cy="200" r="20" fill="hsl(var(--background))" stroke="currentColor" strokeWidth="1.5" />
      <path d="M 151 211 A 14 14 0 0 0 169 211" stroke="currentColor" strokeWidth="1" fill="none" />
      <line x1="160" y1="214" x2="160" y2="217" stroke="currentColor" strokeWidth="1" />
      <line x1="151" y1="211" x2="149" y2="214" stroke="currentColor" strokeWidth="1" />
      <line x1="169" y1="211" x2="171" y2="214" stroke="currentColor" strokeWidth="1" />
      <circle cx="160" cy="200" r="1.5" fill="currentColor" />
      <line x1="160" y1="200" x2="160" y2="216" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
      <circle cx="140" cy="200" r="2" fill="currentColor" />
      <circle cx="180" cy="200" r="2" fill="currentColor" />

      {/* Right galvanometer (with deflected needle) */}
      <circle cx="480" cy="200" r="20" fill="hsl(var(--background))" stroke="currentColor" strokeWidth="1.5" />
      <path d="M 471 211 A 14 14 0 0 0 489 211" stroke="currentColor" strokeWidth="1" fill="none" />
      <line x1="480" y1="214" x2="480" y2="217" stroke="currentColor" strokeWidth="1" />
      <line x1="471" y1="211" x2="469" y2="214" stroke="currentColor" strokeWidth="1" />
      <line x1="489" y1="211" x2="491" y2="214" stroke="currentColor" strokeWidth="1" />
      <circle cx="480" cy="200" r="1.5" fill="currentColor" />
      <line x1="480" y1="200" x2="472" y2="213.8" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
      <circle cx="460" cy="200" r="2" fill="currentColor" />
      <circle cx="500" cy="200" r="2" fill="currentColor" />

      {/* Motion arrow above the moving magnet (now centred on the new
          magnet midpoint x=465). */}
      <line x1="450" y1="65" x2="480" y2="65" stroke="currentColor" strokeWidth="1.5" />
      <polyline points="474,61 480,65 474,69" stroke="currentColor" strokeWidth="1.5" strokeLinejoin="round" strokeLinecap="round" fill="none" />

      {/* Induced current — curved arrow above the right coil */}
      <path d="M 560 55 C 550 55, 546 60, 546 70" fill="none" stroke="currentColor" strokeWidth="1.5" />
      <polyline points="542,66 546,70 550,66" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinejoin="round" strokeLinecap="round" />

      {/* Lead current arrowheads — placed on the new lead segments. By
          Lenz's law, with N pole approaching the coil's left end, the
          induced current opposes the flux change → current EXITS the
          coil at the top-left lead (down-arrow on x=500 vertical) and
          ENTERS the coil at the bottom-right lead (up-arrow on x=596
          vertical). */}
      <polyline points="496,121 500,125 504,121" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinejoin="round" strokeLinecap="round" />
      <polyline points="592,129 596,125 600,129" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinejoin="round" strokeLinecap="round" />

      {/* Layer 5: text labels */}
      <text fontFamily="inherit" fontSize="12" fill="currentColor" textAnchor="middle">
        <tspan x="125" y="94" dominantBaseline="middle">{t('ch1_6.faradayPoleS')}</tspan>
        <tspan x="165" y="94" dominantBaseline="middle">{t('ch1_6.faradayPoleN')}</tspan>
        <tspan x="445" y="94" dominantBaseline="middle">{t('ch1_6.faradayPoleS')}</tspan>
        <tspan x="485" y="94" dominantBaseline="middle">{t('ch1_6.faradayPoleN')}</tspan>
      </text>

      <text fontFamily="inherit" fontSize="12" fill="currentColor" textAnchor="middle">
        <tspan x="160" y="192">{t('ch1_6.faradayMeterG')}</tspan>
        <tspan x="480" y="192">{t('ch1_6.faradayMeterG')}</tspan>
      </text>

      {/* Identify the meter symbol — without this label many readers
          don't recognise "G" as the galvanometer convention. */}
      <text fontFamily="inherit" fontSize="11" fontStyle="italic" fill="currentColor" textAnchor="middle" opacity="0.75">
        <tspan x="160" y="234">{t('ch1_6.faradayMeterLabel')}</tspan>
        <tspan x="480" y="234">{t('ch1_6.faradayMeterLabel')}</tspan>
      </text>

      {/* Captions are now rendered as HTML below — they auto-wrap when
          long instead of overflowing the SVG panel width. */}

      <text fontFamily="inherit" fontStyle="italic" fontWeight="700" fontSize="14" fill="currentColor">
        <tspan x="465" y="56" textAnchor="middle">{t('ch1_6.faradayVelocityLabel')}</tspan>
        <tspan x="566" y="54" textAnchor="start">{t('ch1_6.heroCurrentLabel')}</tspan>
        <tspan x="494" y="128" textAnchor="end">{t('ch1_6.heroCurrentLabel')}</tspan>
        <tspan x="602" y="128" textAnchor="start">{t('ch1_6.heroCurrentLabel')}</tspan>
      </text>
    </svg>
    {/* HTML captions — auto-wrap, two-column grid mirrors the SVG
        panel layout. The right panel originally needed two i18n keys
        because SVG <text> couldn't wrap; now they're joined with a
        space and word-wrap takes care of the rest. */}
    <figcaption className="grid grid-cols-2 gap-4 mt-2 text-center text-sm leading-snug text-foreground">
      <span>{t('ch1_6.faradayLeftCaption')}</span>
      <span>{t('ch1_6.faradayRightCaption1')} {t('ch1_6.faradayRightCaption2')}</span>
    </figcaption>
    </figure>
  )
}
